// AUTO-GENERATED from ./assets/*.png (W5-31; per-location in W9-03; CB slot
// filled + LVA refreshed with the owner's official carimbo in W12-32). The
// OsteoJP signature + carimbo blocks, owner-supplied (2026-07-23). Each is a
// LOCATION-SPECIFIC stamp - NOT a generic clinic stamp; printing one location's
// stamp on another's declaration was the CB "erro grave" (QA item 2), so the
// mapping below is strict and a missing slot renders BLANK, never a fallback.
//
// Base64-inlined so the bytes are always bundled in the serverless build
// (pdf-lib embeds them). Do not edit by hand - regenerate from the assets.
//
//   linda-a-velha : signature-stamp-linda-a-velha.png (1210x402, JP signature)
//   castelo-branco: signature-stamp-castelo-branco.png (962x476)
export const SIGNATURE_STAMP_LINDA_A_VELHA_PNG_BASE64 =
  "";

export const SIGNATURE_STAMP_CASTELO_BRANCO_PNG_BASE64 =
  "";

/**
 * Per-location carimbo slots, keyed by `normalizeLocationKey` - the SAME
 * canonical key the localidade line already resolves through
 * (`location-contacts.ts`). W9-03 (CB QA item 2, "erro grave"); W12-32 fills CB.
 *
 * A key mapping to `null` is a DEFINED EMPTY SLOT: that location has no stamp
 * asset yet, so its declaration renders a clean blank stamp area for a physical
 * stamp - never another clinic's carimbo. Filling a slot is a one-line change
 * once the owner supplies the image.
 *
 * Before W9-03 there was ONE zero-argument accessor returning the LV block for
 * every location, which is exactly why a CB declaration printed the LV stamp.
 */
const STAMP_BASE64_BY_LOCATION: Readonly<Record<string, string | null>> = {
  "linda-a-velha": SIGNATURE_STAMP_LINDA_A_VELHA_PNG_BASE64,
  // W12-32: CB slot filled with the owner's official Castelo Branco carimbo.
  "castelo-branco": SIGNATURE_STAMP_CASTELO_BRANCO_PNG_BASE64,
  // Montemor-o-Novo is deliberately absent, mirroring location-contacts.ts
  // ("intentionally absent - opening, no confirmed contacts yet"). An unknown
  // key resolves to null below, so it also renders a blank stamp area.
};

/**
 * The carimbo bytes for a location, or null for a blank stamp area.
 *
 * Returns null for: a location with a defined-but-empty slot, an unknown
 * location, and a missing location. The fallback is ALWAYS blank, never another
 * clinic's stamp - that substitution was the reported defect.
 */
export function signatureStampBytesForLocation(locationKey: string | null): Uint8Array | null {
  if (!locationKey) return null;
  const b64 = STAMP_BASE64_BY_LOCATION[locationKey];
  if (!b64) return null;
  return Uint8Array.from(Buffer.from(b64, "base64"));
}
